class BorrowingRecord:
    def __init__(self, member, book_item, loan_days=14):
        self.member = member
        self.book_item = book_item
        self.borrow_date = datetime.now()
        self.due_date = self.borrow_date + timedelta(days=loan_days)
        self.return_date = None

    def calculate_fine(self, fine_per_day=1.0):
        if self.return_date and self.return_date > self.due_date:
            overdue_days = (self.return_date - self.due_date).days
            return overdue_days * fine_per_day
        return 0.0

from collections import Counter

def first_unique_char(s):
    count = Counter(s)
    for i, ch in enumerate(s):
        if count[ch] == 1:
            return i  # or return ch
    return -1

# Return the character itself
print(first_unique_char("leetcode"))   # 0 (index of 'l')
print(first_unique_char("loveleetcode")) # 2 (index of 'v')

# Streaming version using ordered dict
def streaming_first_unique(stream):
    from collections import OrderedDict
    seen_once = OrderedDict()
    seen_more = set()
    for ch in stream:
        if ch in seen_more:
            continue
        if ch in seen_once:
            del seen_once[ch]
            seen_more.add(ch)
        else:
            seen_once[ch] = True
    return next(iter(seen_once), None)

from abc import ABC, abstractmethod

# DIP + OCP example
class IExporter(ABC):
    @abstractmethod
    def export(self, data): pass

class PdfExporter(IExporter):
    def export(self, data):
        return f"PDF: {data}"

class HtmlExporter(IExporter):
    def export(self, data):
        return f"<html>{data}</html>"

# ReportGenerator depends on abstraction, not concrete class
class ReportGenerator:
    def __init__(self, exporter: IExporter):
        self.exporter = exporter

    def generate(self, data):
        return self.exporter.export(data)

